/// A type that can describe itself as a JSON Schema. Conformance is generated by `@Schemable`.
public protocol ADJSONSchemaProviding {
    /// The compiled schema describing this type. Built once and cached; safe to validate concurrently.
    static var jsonSchema: JSONSchema { get }

    /// The schema as a rooted JSON document, carrying `$schema` when the type opts into a dialect via
    /// `@Schemable(dialect:)`. This is the canonical text to embed in a larger document (e.g. an MCP
    /// `tools/list` payload). Unlike ``__adjsonSchemaText`` it is API, not SPI.
    static var jsonSchemaText: String { get }

    /// SPI used by `@Schemable` to compose nested types into a parent's schema text. A *bare*
    /// fragment that never carries `$schema` (the dialect lives on the root only). The double
    /// underscore signals "do not call directly" ‚Äî use ``jsonSchemaText`` or ``jsonSchema``.
    static var __adjsonSchemaText: String { get }
}

extension ADJSONSchemaProviding {
    /// Safety net for hand-written conformances: a dialect-less root is just the bare fragment. The
    /// `@Schemable` macro overrides this with the dialect-aware document when a dialect is selected.
    public static var jsonSchemaText: String { __adjsonSchemaText }
}

/// The JSON Schema dialect a `@Schemable` type advertises via its root `$schema`. The default,
/// ``none``, omits `$schema` entirely (byte-identical to emitting no dialect). The validator is a
/// 2020-12 subset, so the choice only affects the emitted `$schema` literal, not validation.
public enum SchemaDialect: Sendable {
    /// No `$schema` keyword is emitted.
    case none
    /// `http://json-schema.org/draft-07/schema#` ‚Äî what MCP `tools/list` expects.
    case draft7
    /// `https://json-schema.org/draft/2020-12/schema`.
    case draft2020_12
}

extension JSONSchema {
    /// A schema that accepts every instance. Serves as the non-throwing fallback for
    /// macro-generated schemas, whose text is well-formed by construction, so the generated
    /// ``ADJSONSchemaProviding/jsonSchema`` never traps and needs no `try` at the call site.
    public static let permitAll = JSONSchema(permitAll: ())

    // A boolean-`true` root accepts everything; validation never reads the document for such a
    // node, so an empty backing document is sufficient (and avoids parsing a constant).
    private init(permitAll: Void) {
        var root = SchemaNode()
        root.boolean = true
        self.nodes = [root]
        self.rootIndex = 0
        self.registry = [:]
        self.document = JSONDocument(backing: .bytes([]), tape: [])
    }
}

/// Generates a compiled JSON Schema for a `struct` from its stored properties, at compile time ‚Äî
/// no instance and no `Mirror` reflection, unlike ``JSONSchema/describe(_:)``. Validate with
/// `T.jsonSchema`.
///
/// First cut: `struct`s whose stored properties have explicit type annotations. Scalars, arrays,
/// string-keyed dictionaries, and optionals map directly; nested custom types must also be
/// `@Schemable` so their schema can be composed into the parent. Types with custom `CodingKeys`,
/// and directly self-referential types, are left undescribed (a warning is emitted).
@attached(
    extension,
    conformances: ADJSONSchemaProviding,
    names: named(jsonSchema), named(jsonSchemaText), named(__adjsonSchemaText), named(__adjsonSchemaCompiled)
)
public macro Schemable(dialect: SchemaDialect = .none) =
    #externalMacro(module: "ADJSONMacros", type: "SchemableMacro")
